+    /// Zero-cost draft using Prompt Lookup Decoding (PLD)
+    /// Finds n-gram matches in token history and predicts continuation
+    /// Returns: number of tokens drafted (0 if no match found)
+    pub fn draftFromHistory(
+        history: []const u32,
+        draft_buf: []u32,
+        n_gram_size: usize,
+    ) usize {
+        const max_drafts = draft_buf.len;
+        if (history.len < n_gram_size + 1) return 0;
+
+        // The pattern to match: last n_gram_size tokens
+        const needle = history[history.len - n_gram_size ..];
+
+        // Scan backwards through history to find previous occurrence
+        // Start from position that could have tokens following it
+        var i: usize = history.len - n_gram_size - 1;
+        while (i > 0) : (i -= 1) {
+            // Check if history[i..i+n_gram_size] matches needle
+            if (std.mem.eql(u32, history[i .. i + n_gram_size], needle)) {
+                // Found match! Copy tokens that followed it
+                var drafted: usize = 0;
+                var src_idx = i + n_gram_size;
+                // Don't copy past the current needle position
+                while (drafted < max_drafts and src_idx < history.len - n_gram_size) {
+                    draft_buf[drafted] = history[src_idx];
+                    drafted += 1;
+                    src_idx += 1;
+                }
+                return drafted;
+            }
+        }
+
+        return 0; // No match found
+    }
