+    /// Speculative decoding with Prompt Lookup Decoding (zero-cost drafting)
+    /// 1. Draft: Use n-gram history matching (0 SSD cost)
+    /// 2. Verify: Run batch through model (1 SSD cost per batch)
+    /// Returns: number of tokens generated this round
+    pub fn speculativeDecodePLD(
+        self: *Self,
+        history: *std.ArrayListUnmanaged(u32),
+        start_pos: u32,
+        max_tokens: usize,
+    ) !struct { generated: usize, pld_hits: usize, pld_misses: usize } {
+        const DRAFT_SIZE: usize = 5;
+        const N_GRAM_SIZE: usize = 2; // Match last 2 tokens (bigram)
+
+        var draft_buf: [DRAFT_SIZE]u32 = undefined;
+        var tokens_generated: usize = 0;
+        var pos = start_pos;
+        var pld_hits: usize = 0;
+        var pld_misses: usize = 0;
+
+        while (tokens_generated < max_tokens) {
+            // === PHASE 1: ZERO-COST DRAFT ===
+            const drafted = draftFromHistory(
+                history.items,
+                &draft_buf,
+                N_GRAM_SIZE,
+            );
+
+            if (drafted == 0) {
+                // No pattern found - fall back to single token generation
+                pld_misses += 1;
+                const last_tok = history.items[history.items.len - 1];
+                const logits = try self.forwardTrueSingleSubmit(last_tok, pos);
+                const next_tok = self.sampleGreedy(logits);
+                try history.append(self.allocator, next_tok);
+                pos += 1;
+                tokens_generated += 1;
+
+                // Check for EOS
+                if (next_tok == 2) break;
+                continue;
+            }
+
+            // Found n-gram match!
+            pld_hits += 1;
+            log.info("PLD: Drafted {} tokens from history (n-gram match)", .{drafted});
+
+            // === PHASE 2: BATCH VERIFY ===
+            // Build position array for batch
+            var positions: [DRAFT_SIZE]u32 = undefined;
+            for (0..drafted) |i| {
+                positions[i] = pos + @as(u32, @intCast(i));
+            }
+
+            // Allocate batch logits output
+            var batch_logits_ptrs: [DRAFT_SIZE][]f32 = undefined;
+            var batch_logits_storage: [DRAFT_SIZE][32000]f32 = undefined;
+            for (0..drafted) |i| {
+                batch_logits_ptrs[i] = &batch_logits_storage[i];
+            }
+
+            // Run all draft tokens through model in one batch
+            const draft_slice = draft_buf[0..drafted];
+            const pos_slice = positions[0..drafted];
+            try self.forwardBatchedLayerByLayer(draft_slice, pos_slice, batch_logits_ptrs[0..drafted]);
+
+            // Check each draft token against model prediction
+            var accepted: usize = 0;
+            for (0..drafted) |i| {
+                const logits = batch_logits_ptrs[i];
+                const model_pred = self.sampleGreedy(logits);
+
+                if (draft_buf[i] == model_pred) {
+                    // Match! Accept this token
+                    try history.append(self.allocator, draft_buf[i]);
+                    accepted += 1;
+                } else {
+                    // Mismatch - use model's prediction and stop
+                    try history.append(self.allocator, model_pred);
+                    accepted += 1;
+                    log.info("PLD: Accepted {}/{} tokens (mismatch at {})", .{ accepted, drafted, i });
+                    break;
+                }
+            }
+
+            // If all matched, log it
+            if (accepted == drafted) {
+                log.info("PLD: All {} draft tokens accepted!", .{drafted});
+            }
+
+            pos += @as(u32, @intCast(accepted));
+            tokens_generated += accepted;
+
+            // Check for EOS
+            if (history.items[history.items.len - 1] == 2) break;
+        }
+
+        return .{
+            .generated = tokens_generated,
+            .pld_hits = pld_hits,
+            .pld_misses = pld_misses,
+        };
+    }
